public class Template {
    abstract static class Report {
        final void generate() {
            header();
            body();
            footer();
        }
        void header() { System.out.println("=== Report ==="); }
        abstract void body();
        void footer() { System.out.println("--- End ---"); }
    }
    static class SalesReport extends Report {
        void body() { System.out.println("Sales: $1000"); }
    }
    public static void main(String[] args) {
        new SalesReport().generate();
    }
}
